package com.khanh.fooddelivery.restaurant_service.entity;
import com.khanh.fooddelivery.restaurant_service.common.entity.BaseAuditEntity; import com.khanh.fooddelivery.restaurant_service.enums.*; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; import java.util.UUID;
@Entity @Table(name="restaurants") @Getter @Setter @NoArgsConstructor
public class Restaurant extends BaseAuditEntity {@Id private UUID id; @Column(nullable=false) private UUID ownerUserId; @OneToOne(fetch=FetchType.LAZY) @JoinColumn(name="partner_application_id",unique=true) private RestaurantPartnerApplication partnerApplication; @Column(nullable=false,unique=true) private String restaurantCode; @Column(nullable=false) private String name; private String legalName; @Column(columnDefinition="text") private String description; private String logoUrl; private String coverImageUrl; private String phoneNumber; private String email; private String taxCode; @Enumerated(EnumType.STRING) @Column(nullable=false) private RestaurantStatus status; @Enumerated(EnumType.STRING) @Column(nullable=false) private RestaurantVerificationStatus verificationStatus; @Column(nullable=false) private BigDecimal averageRating=BigDecimal.ZERO; @Column(nullable=false) private long totalReviews; @Version private long version; @PrePersist void id(){if(id==null)id=UUID.randomUUID();}}
